html:
{% set project = frappe.get_doc('ilL-Project', doc.ill_project) if doc.ill_project else None %}
{% set customer = frappe.get_doc('Customer', doc.customer) if doc.customer else None %}
<style>
  @page { size: landscape; margin: 12mm; }
  .schedule { font-family: Arial, Helvetica, sans-serif; font-size: 8px; color: #333; }
  .schedule h1 { font-size: 14px; color: #1a365d; margin: 0 0 2px 0; }
  .schedule .accent-bar { height: 2px; background: #1a365d; margin-bottom: 6px; }
  .schedule h2 { font-size: 11px; color: #4a5568; margin: 0 0 8px 0; font-weight: normal; }
  .schedule .info-bar { background: #f7fafc; border: 1px solid #e2e8f0; border-radius: 3px; padding: 5px 10px; margin-bottom: 10px; font-size: 7.5px; }
  .schedule .info-bar .lbl { color: #4a5568; font-weight: bold; margin-right: 3px; }
  .schedule .info-bar span { margin-right: 18px; }
  .schedule table { width: 100%; border-collapse: collapse; margin-top: 4px; }
  .schedule th, .schedule td { border: 1px solid #e2e8f0; padding: 3px 5px; text-align: left; font-size: 7.5px; vertical-align: top; }
  .schedule th { background-color: #1a365d; color: #fff; font-weight: bold; }
  .schedule tbody tr:nth-child(even) { background-color: #f7fafc; }
  .schedule .other-mfr { background-color: #fffbe6 !important; }
  .schedule .text-right { text-align: right; }
  .schedule .desc-detail { color: #4a5568; }
  .schedule .footer { text-align: center; font-size: 7px; color: #a0aec0; margin-top: 12px; border-top: 1px solid #e2e8f0; padding-top: 4px; }
</style>
<div class="schedule">
  <h1>{{ doc.schedule_name }}</h1>
  <div class="accent-bar"></div>
  {% if project %}<h2>{{ project.project_name }}</h2>{% endif %}

  <div class="info-bar">
    {% if customer %}<span><span class="lbl">Customer:</span> {{ customer.customer_name or customer.name }}</span>{% endif %}
    <span><span class="lbl">Date:</span> {{ frappe.format_date(frappe.utils.nowdate()) }}</span>
    <span><span class="lbl">Status:</span> {{ doc.status }}</span>
    {% if doc.version %}<span><span class="lbl">Version:</span> {{ doc.version }}</span>{% endif %}
  </div>

  <table>
    <thead>
      <tr>
        <th style="width:40px;text-align:center;">Fixture<br>Type</th>
        <th>Type</th>
        <th>Qty</th>
        <th>Location</th>
        <th>Description</th>
        <th>Req. (mm)</th>
        <th>Mfg. (mm)</th>
        <th>Notes</th>
      </tr>
    </thead>
    <tbody>
      {% for line in doc.lines %}
      {% set fixture = frappe.get_doc('ilL-Configured-Fixture', line.configured_fixture) if line.configured_fixture else None %}
      <tr class="{{ 'other-mfr' if line.manufacturer_type == 'OTHER' else '' }}">
        <td style="text-align:center;">{{ line.line_id or line.idx }}</td>
        <td>{% if line.manufacturer_type in ['ILLUMENATE', 'ACCESSORY'] %}ilLumenate Lighting{% elif line.manufacturer_type == 'OTHER' %}{{ line.manufacturer_name or 'Other' }}{% else %}{{ line.manufacturer_type }}{% endif %}</td>
        <td>{{ line.qty }}</td>
        <td>{{ line.location or '-' }}</td>
        <td>
          {% if line.manufacturer_type == 'ILLUMENATE' and fixture %}
            <strong>{{ fixture.name }}</strong>
            {% set optical = [] %}
            {% if fixture.cct %}{% do optical.append(fixture.cct) %}{% endif %}
            {% if fixture.cri %}{% do optical.append(fixture.cri ~ ' CRI') %}{% endif %}
            {% if fixture.environment_rating %}{% do optical.append(fixture.environment_rating) %}{% endif %}
            {% if optical %}<br><span class="desc-detail">{{ optical | join(' &middot; ') }}</span>{% endif %}
            {% set phys = [] %}
            {% if fixture.mounting_method %}{% do phys.append(fixture.mounting_method) %}{% endif %}
            {% if fixture.finish %}{% do phys.append(fixture.finish) %}{% endif %}
            {% if fixture.lens_appearance %}{% do phys.append(fixture.lens_appearance) %}{% endif %}
            {% if phys %}<br><span class="desc-detail">{{ phys | join(' &middot; ') }}</span>{% endif %}
          {% elif line.manufacturer_type == 'ILLUMENATE' and not fixture %}
            <strong>{{ line.fixture_template or 'Unknown' }}</strong>
            <br><span class="desc-detail" style="color:#856404;">&#9888; Not configured</span>
          {% elif line.manufacturer_type == 'OTHER' %}
            <strong>{{ line.manufacturer_name or '' }}</strong>
            {% if line.fixture_model_number %}<br><span class="desc-detail">{{ line.fixture_model_number }}</span>{% endif %}
          {% elif line.manufacturer_type == 'ACCESSORY' %}
            <strong>{{ line.accessory_item_name or line.accessory_item or '' }}</strong>
            {% if line.accessory_product_type %}<br><span class="desc-detail">{{ line.accessory_product_type }}</span>{% endif %}
          {% else %}
            <em>-</em>
          {% endif %}
        </td>
        <td>{{ fixture.requested_overall_length_mm if fixture else '-' }}</td>
        <td>{{ fixture.manufacturable_overall_length_mm if fixture else (line.manufacturable_length_mm or '-') }}</td>
        <td>{{ line.notes or '-' }}</td>
      </tr>
      {% endfor %}
    </tbody>
  </table>

  {% if doc.notes %}
  <div style="margin-top: 10px;">
    <strong>Schedule Notes:</strong>
    <p>{{ doc.notes }}</p>
  </div>
  {% endif %}

  <div class="footer">ilLumenate Lighting | Generated {{ frappe.format_date(frappe.utils.nowdate()) }}</div>
</div>
